30	void Help::printCommands() {
31	    int index = 0;
32	    auto callback = [&](Command* command) -> bool {
33	        LOGI("%12s  ", command->get().c_str());
34	        ++index;
35	        if (!(index % ROW_NUM))
36	            ENTER();
37	        return false;
38	    };
39	    CommandManager::ForeachCommand(callback);
40	    if (index % ROW_NUM)
41	        ENTER();
42	}
