25	int MmapCommand::main(int argc, char* const argv[]) {
26	    if (!CoreApi::IsReady() || argc < 3)
27	        return 0;
28	
29	    int opt;
30	    char* file = nullptr;
31	    uint64_t offset = 0x0;
32	    int remove = 0;
33	    int option_index = 0;
34	    optind = 0; // reset
35	    static struct option long_options[] = {
36	        {"offset",  required_argument,  0,  'o'},
37	        {"remove-mmap",  no_argument,   0,   1 },
38	        {"remove-overlay", no_argument, 0,   2 },
39	        {0, 0,                          0,   0 },
40	    };
41	
42	    while ((opt = getopt_long(argc, argv, "o:012",
43	                long_options, &option_index)) != -1) {
44	        switch (opt) {
45	            case 'o':
46	                offset = Utils::atol(optarg);
47	                break;
48	            case 1:
49	                remove |= REMOVE_MMAP;
50	                break;
51	            case 2:
52	                remove |= REMOVE_OVERLAY;
53	                break;
54	        }
55	    }
56	
57	    if (optind == argc) {
58	        MmapCommand::usage();
59	        return 0;
60	    }
61	
62	    uint64_t begin = Utils::atol(argv[optind]) & CoreApi::GetVabitsMask();
63	    if (argc - optind > 1) file = argv[optind + 1];
64	
65	    LoadBlock* block = CoreApi::FindLoadBlock(begin, false);
66	    if (!block)
67	        throw InvalidAddressException(begin);
68	
69	    if (!remove) {
70	        block->setMmapFile(file, offset);
71	        auto callback = [&](LinkMap* map) -> bool {
72	            if (block == map->block()) {
73	                map->ReadSymbols();
74	                return true;
75	            }
76	            return false;
77	        };
78	        CoreApi::ForeachLinkMap(callback);
79	    } else {
80	        if (remove & REMOVE_MMAP)
81	            block->removeMmap();
82	
83	        if (remove & REMOVE_OVERLAY)
84	            block->removeOverlay();
85	    }
86	
87	    return 0;
88	}
