80	int RemoteCommand::OptionRead(int argc, char* const argv[]) {
81	    int opt;
82	    int option_index = 0;
83	    optind = 0; // reset
84	    static struct option long_options[] = {
85	        {"pid",     required_argument, 0, 'p'},
86	        {0,         0,                 0,  0 },
87	    };
88	
89	    int pid = 0;
90	    if (CoreApi::IsRemote())
91	        pid = Env::CurrentRemotePid();
92	    uint64_t end = 0;
93	    while ((opt = getopt_long(argc, argv, "p:e:",
94	                long_options, &option_index)) != -1) {
95	        switch (opt) {
96	            case 'p':
97	                pid = std::atoi(optarg);
98	                break;
99	            case 'e':
100	                end = Utils::atol(optarg);
101	                break;
102	        }
103	    }
104	
105	    if (optind >= argc)
106	        return 0;
107	
108	    std::unique_ptr<Opencore> opencore = std::make_unique<Opencore>();
109	    opencore->StopTheWorld(pid);
110	
111	    uint64_t value[ELF_PAGE_SIZE / 8];
112	    memset(value, 0x0, ELF_PAGE_SIZE);
113	
114	    uint64_t begin = Utils::atol(argv[optind]);
115	    if (optind < argc - 1)
116	        end = begin + std::atoi(argv[optind + 1]) * 0x8;
117	
118	    if (!RemoteCommand::Read(pid, begin, sizeof(value), (uint8_t *)&value))
119	        return 0;
120	
121	    int count = RoundUp((end - begin) / 8, 2);
122	    if (begin >= end || !count) {
123	        std::string ascii = Utils::ConvertAscii(*value, 8);
124	        LOGI(ANSI_COLOR_CYAN "%" PRIx64 "" ANSI_COLOR_RESET ": %016" PRIx64 "  %s\n", begin, (*value), ascii.c_str());
125	    } else {
126	        for (int i = 0; i < count && i < 512; i += 2) {
127	            LOGI(ANSI_COLOR_CYAN "%" PRIx64 "" ANSI_COLOR_RESET ": %016" PRIx64 "  %016" PRIx64 "  %s%s\n", (begin + i * 8), value[i], value[i + 1],
128	                    Utils::ConvertAscii(value[i], 8).c_str(), Utils::ConvertAscii(value[i + 1], 8).c_str());
129	        }
130	    }
131	    return 0;
132	}
