181	void RemoteCommand::Write(int pid, uint64_t vaddr, void *buf, uint64_t size) {
182	#ifdef __ARM64__
183	    vaddr &= ((1ULL << 56) - 1);
184	#endif
185	    char filename[32];
186	    snprintf(filename, sizeof(filename), "/proc/%d/mem", pid);
187	    int fd = open(filename, O_RDWR);
188	    if (fd < 0) {
189	        LOGE("open %s fail.\n", filename);
190	        return;
191	    }
192	
193	    if (pwrite64(fd, buf, size, vaddr) < 0)
194	        LOGE("write %" PRIx64 " fail.\n", vaddr);
195	
196	    close(fd);
197	}
198	
199	bool RemoteCommand::Read(int pid, uint64_t vaddr, uint64_t size, uint8_t* buf) {
200	#ifdef __ARM64__
201	    vaddr &= ((1ULL << 56) - 1);
202	#endif
203	    char filename[32];
204	    snprintf(filename, sizeof(filename), "/proc/%d/mem", pid);
205	    int fd = open(filename, O_RDONLY);
206	    if (fd < 0) {
207	        LOGE("open %s fail.\n", filename);
208	        return false;
209	    }
210	
211	    if (pread64(fd, buf, size, vaddr) < 0) {
212	        LOGE("read %" PRIx64 " fail.\n", vaddr);
213	        close(fd);
214	        return false;
215	    }
216	
217	    close(fd);
218	    return true;
219	}
